INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Gwalior', 'ambassador_message', 'hostels', 'IVH - hostel for 1st year 4 sharing (attached washroom)
Satpura - hostel for 1st year 3 sharing
Bh-2 - hostel for 2nd year sharing of 2 (if CG is more than 8 can have chance of single room)
Bh-1,Bh-3- hostels for 3rd, 4th,5 th year single room
Gh- all girls sharing same as boys
IVH or satpura based on branch,Mess will in that same hostels
1st year', 'ABV-IIITM Gwalior boys hostels: IVH (1st year, 4-sharing with attached washroom), Satpura (1st year, 3-sharing), BH-2 (2nd year, 2-sharing; CG above 8 can get single room), BH-1 and BH-3 (3rd, 4th, 5th year, single rooms). GH is the girls hostel with same sharing pattern. First year students are allocated IVH or Satpura based on branch, and the mess is in the same hostel.', 5, '31/03/26 5:52 pm', '31/03/26 5:57 pm', 'whatsapp');

