INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIIT Gwalior', 'ambassador_message', 'laundry', 'For 1st year we have laundry service for 800 per month
